  "type": "DRAG_FILL",
  "lessonText": "Put your cooking skills to the test with this practical challenge.",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks to complete the recipe for a basic omelette.",
        "codeTemplate": "To make a basic omelette, whisk ___ eggs, add ___ salt, and cook in ___ butter.",
        "options": [
          "2",
          "1 tsp",
          "1 tbsp",
          "3"
        ],
        "correctAnswer": "2,1 tsp,1 tbsp",
        "explanation": "You need 2 eggs, 1 tsp of salt, and 1 tbsp of butter for a perfect omelette."
      },
      {
        "instruction": "Complete the steps for making a simple salad.",
        "codeTemplate": "Start by chopping ___ lettuce, adding ___ tomatoes, and drizzling with ___ olive oil.",
        "options": [
          "1 head",
          "2",
          "2 tbsp",
          "3"
        ],
        "correctAnswer": "1 head,2,2 tbsp",
        "explanation": "A simple salad requires 1 head of lettuce, 2 tomatoes, and 2 tbsp of olive oil."
      }
    ]
  }
}
